{
  "templateId": "common-template-1",
  "templateVersion": 1,
  "title": "CCTV Commissioning Report",
  "wizardSteps": [
    {
      "key": "header",
      "title": "Header",
      "sections": [
        "hdr"
      ]
    },
    {
      "key": "checklist",
      "title": "Checklist",
      "sections": [
        "chk"
      ]
    },
    {
      "key": "signatures",
      "title": "Signatures",
      "sections": [
        "sigs"
      ]
    },
    {
      "key": "review",
      "title": "Review",
      "sections": []
    }
  ],
  "sections": [
    {
      "id": "hdr",
      "type": "header",
      "title": "COMMISSIONING REPORT — CCTV",
      "fields": [
        {
          "key": "vendor",
          "label": "VENDOR",
          "type": "text",
          "default": "STRATOS INFRA TECHNOLOGIES PRIVATE LIMITED",
          "readonly": true
        },
        {
          "key": "project",
          "label": "PROJECT",
          "type": "text",
          "bind": "project.project_name",
          "readonly": true
        },
        {
          "key": "location",
          "label": "LOCATION",
          "type": "text",
          "bind": "project.location.full",
          "readonly": true
        },
        {
          "key": "date",
          "label": "DATE",
          "type": "date",
          "required": true
        }
      ]
    },
    {
      "id": "chk",
      "type": "checklist",
      "title": "CCTV Commissioning Checklist:",
      "columns": [
        {
          "key": "slno",
          "label": "S.No"
        },
        {
          "key": "particular",
          "label": "Description"
        },
        {
          "key": "result",
          "label": "Result"
        },
        {
          "key": "remarks",
          "label": "Remarks"
        }
      ],
      "items": [
        {
          "id": "q1",
          "particular": "Location of Control Equipments (accessible)",
          "result": {
            "type": "select",
            "options": [
              "YES",
              "NO",
              "N/A"
            ],
            "default": "YES"
          },
          "remarks": {
            "type": "text"
          }
        },
        {
          "id": "q2",
          "particular": "Ensure that cables in the Racks, to the cameras are to be dressed appropriately.",
          "result": {
            "type": "select",
            "options": [
              "YES",
              "NO",
              "N/A"
            ],
            "default": "YES"
          },
          "remarks": {
            "type": "text"
          }
        },
        {
          "id": "q3",
          "particular": "Ensure that all DVR / NVR / POE Switch / Cameras & Monitors are placed properly.",
          "result": {
            "type": "select",
            "options": [
              "YES",
              "NO",
              "N/A"
            ],
            "default": "YES"
          },
          "remarks": {
            "type": "text"
          }
        },
        {
          "id": "q4",
          "particular": "Ensure that all the cables from Camera to the Network Switch are properly terminated.",
          "result": {
            "type": "select",
            "options": [
              "YES",
              "NO",
              "N/A"
            ],
            "default": "YES"
          },
          "remarks": {
            "type": "text"
          }
        },
        {
          "id": "q5",
          "particular": "Ensure that cameras are installed as per the approved drawing.",
          "result": {
            "type": "select",
            "options": [
              "YES",
              "NO",
              "N/A"
            ],
            "default": "YES"
          },
          "remarks": {
            "type": "text"
          }
        },
        {
          "id": "q6",
          "particular": "Camera location to be clearly indicated on the monitor during viewing.",
          "result": {
            "type": "select",
            "options": [
              "YES",
              "NO",
              "N/A"
            ],
            "default": "YES"
          },
          "remarks": {
            "type": "text"
          }
        },
        {
          "id": "q7",
          "particular": "Focusing of the camera to be adjusted by proper positioning to obtain optimum result.",
          "result": {
            "type": "select",
            "options": [
              "YES",
              "NO",
              "N/A"
            ],
            "default": "YES"
          },
          "remarks": {
            "type": "text"
          }
        },
        {
          "id": "q8",
          "particular": "Ensure that the camera Enclosure power supply was installed properly.",
          "result": {
            "type": "select",
            "options": [
              "YES",
              "NO",
              "N/A"
            ],
            "default": "YES"
          },
          "remarks": {
            "type": "text"
          }
        },
        {
          "id": "q9",
          "particular": "Ensure that Power supply outlets for the CCTV system were fed by UPS (Optional).",
          "result": {
            "type": "select",
            "options": [
              "YES",
              "NO",
              "N/A"
            ],
            "default": "YES"
          },
          "remarks": {
            "type": "text"
          }
        },
        {
          "id": "q10",
          "particular": "Check the NVR are connected to the security network LAN with Static IP (Optional).",
          "result": {
            "type": "select",
            "options": [
              "YES",
              "NO",
              "N/A"
            ],
            "default": "N/A"
          },
          "remarks": {
            "type": "text"
          }
        },
        {
          "id": "q11",
          "particular": "Operation and maintenance information provided.",
          "result": {
            "type": "select",
            "options": [
              "YES",
              "NO",
              "N/A"
            ],
            "default": "YES"
          },
          "remarks": {
            "type": "text"
          }
        }
      ]
    },
    {
      "id": "sigs",
      "type": "signatures",
      "blocks": [
        {
          "key": "tested_by",
          "label": "TESTED BY"
        },
        {
          "key": "consultant",
          "label": "CONSULTANT"
        },
        {
          "key": "client",
          "label": "CLIENT"
        }
      ]
    }
  ]
}

